```class Solution {
public:
    int findMaxK(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (nums[i] * nums[j] == 0) {
                    return -1;
                }
            }
        }
        int k = 0;
        for (int i = 0; i < n; i++) {
            k = max(k, nums[i] * -1);
        }
        return k;
    }
};
```

